public class FieldHiding {
    static class Parent {
        int x = 10;
        int getX() { return x; }
    }
    static class Child extends Parent {
        int x = 20;  // hides Parent.x
        int getX() { return x; }  // overrides
    }
    public static void main(String[] args) {
        Parent p = new Child();
        System.out.println(p.x);       // field access: compile-time type
        System.out.println(p.getX()); // method call: runtime type
    }
}
